<?php namespace App\Repositories; use App\Repositories\Contracts\RepositoryInterface; use Illuminate\Database\Eloquent\Model; use Illuminate\Database\Eloquent\Collection; use Illuminate\Pagination\LengthAwarePaginator; abstract class BaseRepository implements RepositoryInterface { protected $model; public function __construct(Model $model) { $this->model = $model; } public function all(array $columns = ['*']) { return $this->model->all($columns); } public function find(int $id, array $columns = ['*']) { return $this->model->findOrFail($id, $columns); } public function create(array $data) { return $this->model->create($data); } public function update(int $id, array $data) { $record = $this->find($id); $record->update($data); return $record; } public function delete(int $id) { return $this->find($id)->delete(); } public function paginate(int $perPage = 15, array $columns = ['*']) { return $this->model->paginate($perPage, $columns); } public function findWhere(string $column, $value, array $columns = ['*']) { return $this->model->where($column, $value)->get($columns); } public function findWhereFirst(string $column, $value, array $columns = ['*']) { return $this->model->where($column, $value)->firstOrFail($columns); } public function filter(array $filters) { $query = $this->model->newQuery(); foreach ($filters as $column => $value) { if (!empty($value)) { $query->where($column, 'LIKE', '%' . $value . '%'); } } return $query->get(); } public function sortBy(string $column, string $direction = 'asc') { return $this->model->orderBy($column, $direction)->get(); } }